SELECT ${1:column}, COUNT(*) as ${2:count}
FROM ${3:table_name}
GROUP BY ${1:column};

SELECT ${1:column}, COUNT(*) as ${2:count}
FROM ${3:table_name}
GROUP BY ${1:column}
HAVING COUNT(*) > ${4:threshold};

CREATE TABLE ${1:table_name} (
	${2:id} INT PRIMARY KEY AUTO_INCREMENT,
	${3:column1} ${4:VARCHAR(255)} NOT NULL,
	${5:column2} ${6:TEXT},
	${7:created_at} TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE ${1:table_name} (
	${2:id} INT PRIMARY KEY AUTO_INCREMENT,
	${3:user_id} INT NOT NULL,
	${4:column1} ${5:VARCHAR(255)},
	FOREIGN KEY (${3:user_id}) REFERENCES ${6:users}(${7:id})
);

CREATE VIEW ${1:view_name} AS
SELECT ${2:columns}
FROM ${3:table_name}
WHERE ${4:condition};

SELECT ${1:*}
FROM ${2:table1}
WHERE ${3:column} IN (
	SELECT ${4:column}
	FROM ${5:table2}
	WHERE ${6:condition}
);

CASE
	WHEN ${1:condition1} THEN ${2:result1}
	WHEN ${3:condition2} THEN ${4:result2}
	ELSE ${5:default_result}
END

CASE ${1:column}
	WHEN ${2:value1} THEN ${3:result1}
	WHEN ${4:value2} THEN ${5:result2}
	ELSE ${6:default_result}
END

BEGIN TRANSACTION;

${1:-- SQL statements}

-- If error occurs:
-- ROLLBACK;
-- Otherwise:
COMMIT;

SELECT ${1:columns}
FROM ${2:table1}
WHERE ${3:condition1}

UNION

SELECT ${1:columns}
FROM ${4:table2}
WHERE ${5:condition2};

WITH ${1:cte_name} AS (
	SELECT ${2:columns}
	FROM ${3:table_name}
	WHERE ${4:condition}
)
SELECT ${5:*}
FROM ${1:cte_name};
